SELECT 'What is the Moreška?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška is a traditional sword dance from the town of Korčula, Croatia, in which two armies fight a series of staged battles with real iron swords over the fate of a captured woman. It combines spoken drama, a live brass orchestra, and seven escalating sword-clash figures, and it is widely described as ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Europe''s last surviving authentic war dance","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". In Korčula it has been documented since 1666 and performed by the local community ever since.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'about'::enum_faqs_category, 'en'::enum_faqs_locale, 0, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'What is the Moreška?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Is the Moreška worth seeing?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Yes, the Moreška is the only sword dance of its kind still performed intact in Europe, with real iron swords, a live brass orchestra, and a story acted in archaic 17th-century verse. Similar dances once spanned the Mediterranean, from Spain to the Greek islands; Korčula is the last place it survives complete. For visitors it is loud, dramatic, and rooted in centuries of local identity, an experience that can''t be replicated anywhere else.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'about'::enum_faqs_category, 'en'::enum_faqs_locale, 1, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Is the Moreška worth seeing?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Is the Moreška protected?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Yes, the Moreška is officially recognised as a ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"protected cultural good of the Republic of Croatia","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a status granted by the Ministry of Culture. The designation safeguards its traditional elements, the double-sword technique and the local-dialect dialogue, from commercial dilution and helps preserve them in authentic form.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'about'::enum_faqs_category, 'en'::enum_faqs_locale, 2, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Is the Moreška protected?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Is the Moreška a dance or a play?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"It is both, the Moreška is a \"syncretic\" performance that seamlessly combines a written drama with a sword dance. It opens as a play, with characters speaking in archaic 17th-century Korčulan verse, and then becomes a dance, as two armies fight seven choreographed sword battles.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'about'::enum_faqs_category, 'en'::enum_faqs_locale, 3, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Is the Moreška a dance or a play?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Is there spoken or dramatic text?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Yes, before the fighting begins, the characters speak a scripted dialogue written in an archaic 17th-century Korčulan dialect. This prologue sets up the conflict: the captured Bula declares her loyalty, and the challenge between the two kings is issued before the armies clash.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'about'::enum_faqs_category, 'en'::enum_faqs_locale, 4, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Is there spoken or dramatic text?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Is the Moreška a symbol of Korčula?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Yes, the Moreška is regarded as the cultural symbol of Korčula and a symbol of Croatian intangible heritage. Passed from father to son for generations, it is so central to local identity that the town has a saying, ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"\"You are not a male if you cannot dance Moreška.\"","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'about'::enum_faqs_category, 'en'::enum_faqs_locale, 5, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Is the Moreška a symbol of Korčula?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Does the Moreška have main characters?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Yes, the Moreška has four main characters: the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Bula","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (the captured maiden), ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Osman","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (the White King, her betrothed), ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moro","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (the Black King, her abductor), and ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Otmanović","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (Moro''s father). Around them, two full armies, White and Black, fight the seven battles.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 6, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Does the Moreška have main characters?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Why do the kings fight in the Moreška?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The two kings fight over a woman, the Bula, who has been abducted. Moro, the Black King, has taken the Bula by force and tries to win her love; Osman, the White King and her betrothed, comes to free her. The conflict is not only over the woman but over honour and the sanctity of marriage, and it is settled in seven sword battles.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 7, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Why do the kings fight in the Moreška?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Who is the Bula?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Bula is the captured maiden at the centre of the Moreška, the betrothed of the White King, Osman. She is taken by force by Moro, the Black King, and the entire battle is fought to free her. She represents purity, loyalty, and the object of the hero''s virtue.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 8, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Who is the Bula?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Why is the Bula important?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Bula is important because she is the reason for the entire conflict, the whole sword dance is fought over her. Her steadfast refusal to yield to her captor (","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"\"far more pain for me is your unwanted love than the steel\"","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":") sets the moral stakes: the battle is about honour and loyalty, not just possession. Her liberation at the end marks the triumph of virtue.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 9, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Why is the Bula important?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Who is the Bula''s fiancé?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Bula''s fiancé is Osman, the White King. He arrives to reclaim his betrothed from Moro, who has abducted her, and his army wins the battle that frees her.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 10, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Who is the Bula''s fiancé?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Who is Moro?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moro is the Black King and the abductor in the Moreška. He is the son of Otmanović, and he has taken the Bula by force and tries to win her affection. His army loses the seven battles, and he ends by surrendering his sword at the White King''s feet.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 11, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Who is Moro?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Who is Otmanović?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Otmanović is Moro''s father in the Moreška, a figure of dynastic authority who represents the weight of the enemy army behind his son. He is not himself the Black King; that is Moro.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 12, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Who is Otmanović?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Who is Osman?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Osman is the White King and the hero of the Moreška. He is the Bula''s betrothed and wears red; he represents justice and the rightful lover, and his army always wins, freeing the Bula.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 13, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Who is Osman?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Why is the Bula in chains?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Bula is in chains because she has been abducted and held captive by Moro, the Black King. The performance opens with Moro dragging the chained Bula and trying to win her love, while she refuses; she is freed from her chains only at the end, after the White King''s army wins.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 14, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Why is the Bula in chains?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Which king wins in the end?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The White King, Osman, always wins. The White army (which wears red) defeats the Black army; Moro surrenders his sword at Osman''s feet, and the Bula is freed from her chains. The ending never changes, virtue always wins.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'story'::enum_faqs_category, 'en'::enum_faqs_locale, 15, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Which king wins in the end?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Is the Moreška dynamic?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Yes, the Moreška is highly dynamic. It is a physically intense sword dance in which the combat escalates across seven figures from lyrical circling to a furious, full-speed finale, with iron swords clashing hard enough to throw sparks. The dancers sustain high-energy movement throughout, making it as much an athletic feat as a performance.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'dance'::enum_faqs_category, 'en'::enum_faqs_locale, 16, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Is the Moreška dynamic?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'Are the swords in the Moreška real?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Yes, the swords are real iron, not props. Each weighs about one kilogram, and the dancers strike them together hard enough to produce sparks and a ringing ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"\"bam bam bam\"","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" that echoes off the stone walls of the old town. The double-sword technique, a blade in each hand, is what sets the Moreška apart from other European sword dances.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'dance'::enum_faqs_category, 'en'::enum_faqs_locale, 17, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'Are the swords in the Moreška real?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'How heavy are the swords?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Each sword weighs about one kilogram of iron, and every dancer wields two of them, one in each hand. Historically (until the 1960s) the two swords were of unequal length: a longer one in the right hand for attack and a shorter one in the left for defence.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'dance'::enum_faqs_category, 'en'::enum_faqs_locale, 18, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'How heavy are the swords?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'What is the *sfida*?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"sfida","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" is the challenge that opens the sword dance. The Black King dances alone, a graceful but menacing solo in 6/8 rhythm, to provoke the White King. It is a kinetic declaration of war that leads directly into the entry of both armies and the seven battles.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'dance'::enum_faqs_category, 'en'::enum_faqs_locale, 19, 'published'::enum_faqs_status
WHERE NOT EXISTS (SELECT 1 FROM faqs WHERE question = 'What is the *sfida*?' AND locale = 'en');

INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'How many dance figures does the Moreška have?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška has ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"seven","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" main figures, called ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"kolapi","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", preceded by the opening ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"sfida","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (the challenge). Each figure has a traditional name, Rugier, Moreška, Finta, Moro in dentro, Križ (the Cross), Rugier de fuorivia, and the Final Figure, and they escalate in tempo to a furious finale in 4/4 time.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'dance'::enum_faqs_category, 'en'::enum_faqs_locale, 20, 'published'::enum_faqs_status
