INSERT INTO faqs (question, answer, category, locale, "order", status)
SELECT 'What colours are the two opposing armies?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The two armies are the \"White\" army and the \"Black\" army. Notably, the White army wears ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"red","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", and the Black army wears ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"black","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". The White (red) army represents justice and the rightful claimant, and always wins.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}'::jsonb, 'dance'::enum_faqs_category, 'en'::enum_faqs_locale, 21, 'published'::enum_faqs_status
